+fn git_auth_plan(
+    args: Vec<String>,
+    destination: &str,
+    headers: &[String],
+    inherited_config_count: Option<usize>,
+) -> GitCommandPlan {
+    let first_index = inherited_config_count.unwrap_or(0);
+    let mut env = vec![(
+        "GIT_CONFIG_COUNT".to_string(),
+        (first_index + headers.len()).to_string(),
+    )];
+    for (offset, header) in headers.iter().enumerate() {
+        let index = first_index + offset;
+        env.push((
+            format!("GIT_CONFIG_KEY_{index}"),
+            format!("http.{destination}.extraHeader"),
+        ));
+        env.push((format!("GIT_CONFIG_VALUE_{index}"), header.clone()));
+    }
+    GitCommandPlan { args, env }
+}
+
+fn inherited_git_config_count() -> Option<usize> {
+    env::var("GIT_CONFIG_COUNT")
+        .ok()
+        .and_then(|value| value.parse().ok())
+}
+
+fn git_command(plan: GitCommandPlan, cwd: Option<&Path>) -> Command {
+    let mut command = Command::new("git");
+    if let Some(cwd) = cwd {
+        command.current_dir(cwd);
+    }
+    command.args(plan.args);
+    command.envs(plan.env);
+    command
+}
+
+fn run_git_plan_status(
+    plan: GitCommandPlan,
+    cwd: Option<&Path>,
+    context: &str,
+    failure: &str,
+) -> anyhow::Result<()> {
+    if !git_command(plan, cwd).status().context(context)?.success() {
+        bail!("{failure}");
+    }
+    Ok(())
+}
+
+fn run_git_plan_output(
+    plan: GitCommandPlan,
+    cwd: Option<&Path>,
+    context: &str,
+    failure: &str,
+) -> anyhow::Result<()> {
+    let output = git_command(plan, cwd).output().context(context)?;
+    if !output.status.success() {
+        let stderr = String::from_utf8_lossy(&output.stderr);
+        let stderr = stderr.trim();
+        if !stderr.is_empty() {
+            bail!("{failure}: {stderr}");
+        }
+        bail!("{failure}");
+    }
+    Ok(())
+}
